"""Core statistics for paired model/agent eval comparison — the honest math.

All tests are PAIRED: the two systems are run on the *same* tasks, so per-task outcomes are
correlated and we must not pretend they're independent. Everything here is deterministic given
a seed (reproducibility is the point) and depends only on numpy + the stdlib.
"""
from __future__ import annotations

import math
from statistics import NormalDist

import numpy as np

_NORM = NormalDist()


def proportion_se(p: float, n: int) -> float:
    """Standard error of a single proportion: sqrt(p(1-p)/n)."""
    if n <= 0:
        return float("nan")
    return math.sqrt(p * (1.0 - p) / n)


def paired_permutation_test(diffs, n_resamples: int = 10000, alternative: str = "two-sided",
                            seed: int = 0):
    """Sign-flip (paired) permutation test on per-task differences (candidate - baseline).

    Under H0 the two conditions are exchangeable within each task, i.e. the sign of each
    difference is equally likely to flip. Valid for binary OR continuous/graded scores.
    Returns (observed_mean_difference, p_value). Uses the add-one estimator so p is never 0.
    """
    d = np.asarray(diffs, dtype=float)
    d = d[~np.isnan(d)]
    n = d.size
    if n == 0:
        return 0.0, 1.0
    obs = float(d.mean())
    rng = np.random.default_rng(seed)
    signs = rng.choice(np.array([1.0, -1.0]), size=(n_resamples, n))
    perm = (signs * d).mean(axis=1)
    if alternative == "two-sided":
        count = int(np.sum(np.abs(perm) >= abs(obs) - 1e-12))
    elif alternative == "greater":
        count = int(np.sum(perm >= obs - 1e-12))
    elif alternative == "less":
        count = int(np.sum(perm <= obs + 1e-12))
    else:
        raise ValueError(f"unknown alternative: {alternative}")
    p = (count + 1) / (n_resamples + 1)
    return obs, float(p)


def mcnemar_counts(baseline, candidate):
    """For paired binary outcomes, return (b01, b10):
    b01 = baseline wrong & candidate right (improvements);
    b10 = baseline right & candidate wrong (regressions)."""
    a = np.asarray(baseline, dtype=float)
    b = np.asarray(candidate, dtype=float)
    b01 = int(np.sum((a == 0) & (b == 1)))
    b10 = int(np.sum((a == 1) & (b == 0)))
    return b01, b10


def mcnemar_exact(b01: int, b10: int) -> float:
    """Exact (binomial) two-sided McNemar p-value on the discordant pairs.

    Only the discordant pairs carry information; under H0 each is a fair coin. Exact binomial
    is robust for small discordant counts (where the chi-square approximation misbehaves).
    """
    n = b01 + b10
    if n == 0:
        return 1.0
    k = min(b01, b10)
    tail = sum(math.comb(n, i) for i in range(0, k + 1)) * (0.5 ** n)
    return float(min(1.0, 2.0 * tail))


def bootstrap_diff_ci(diffs, ci: float = 0.95, n_resamples: int = 10000, seed: int = 0):
    """Percentile bootstrap confidence interval for the mean per-task difference."""
    d = np.asarray(diffs, dtype=float)
    d = d[~np.isnan(d)]
    n = d.size
    if n == 0:
        return (float("nan"), float("nan"))
    rng = np.random.default_rng(seed)
    idx = rng.integers(0, n, size=(n_resamples, n))
    means = d[idx].mean(axis=1)
    lo = (1.0 - ci) / 2.0 * 100.0
    hi = (1.0 + ci) / 2.0 * 100.0
    return float(np.percentile(means, lo)), float(np.percentile(means, hi))


def fwer(m: int, alpha: float = 0.05) -> float:
    """Family-wise error rate from m independent comparisons at level alpha: 1-(1-alpha)^m.

    With correlated variants this is an UPPER bound on the false-positive probability.
    """
    return 1.0 - (1.0 - alpha) ** max(1, int(m))


def required_n(effect: float, baseline_acc: float = 0.5, alpha: float = 0.05,
               power: float = 0.8, paired_corr: float = 0.5) -> int:
    """Tasks needed to detect a paired accuracy difference `effect` at the given power.

    Normal approximation; variance of the paired difference is 2*p(1-p)*(1-corr). With the
    default corr=0.5 this matches the rule of thumb that a 3-point gain needs ~1k+ questions
    (cf. Miller 2024). Assumptions are explicit — treat as guidance, not gospel.
    """
    effect = abs(effect)
    if effect <= 0:
        return 0
    p = baseline_acc
    var = 2.0 * p * (1.0 - p) * (1.0 - paired_corr)
    za = _NORM.inv_cdf(1.0 - alpha / 2.0)
    zb = _NORM.inv_cdf(power)
    n = (za + zb) ** 2 * var / (effect ** 2)
    return math.ceil(n)


def min_detectable_effect(n: int, baseline_acc: float = 0.5, alpha: float = 0.05,
                          power: float = 0.8, paired_corr: float = 0.5) -> float:
    """Smallest paired accuracy difference detectable at `n` tasks and the given power."""
    if n <= 0:
        return float("inf")
    p = baseline_acc
    var = 2.0 * p * (1.0 - p) * (1.0 - paired_corr)
    za = _NORM.inv_cdf(1.0 - alpha / 2.0)
    zb = _NORM.inv_cdf(power)
    return (za + zb) * math.sqrt(var) / math.sqrt(n)
